/**
 * Map a Nero verdict to a render glyph.
 */
// @kern-source: nero:19
export function verdictGlyph(verdict: string): string {
  return verdict === 'flawed' ? '🔴' : verdict === 'proceed-with-caution' ? '🟡' : verdict === 'sound' ? '🟢' : '⚪';
}

